  publishedAt: Date;
  orgao: string;
  matchCount?: number;
}

interface SearchSurfaceProps {
  // Controlled component: dados fluem via props, não via callback
  results: SearchResult[];
  status: SearchStatus;
  onSearch: (query: string, filters: SearchFilters) => void;  // TanStack Query gerencia async/cancel
  onClear: () => void;
