}

interface SearchFilters {
  secao?: 1 | 2 | 3 | 'extra';
  dateRange?: { from: Date; to: Date };
  orgao?: string;
}

// Implementação: SearchSurface gerencia debounce interno (configurável via debounceMs).
// AbortController é gerenciado pelo TanStack Query (stale/cancel automático).
// a11y: role="search", aria-live="polite" para count de resultados
