### 4.4 DocumentViewer
```typescript
interface DocumentSection {
  id: string;
  type: 'artigo' | 'paragrafo' | 'inciso' | 'titulo' | 'ementa' | 'imagem' | 'tabela' | 'assinatura' | 'anexo';
  content: string;
  depth: number;
  mediaUrl?: string;
  mediaAlt?: string;
  // Para tabelas estruturadas (evita HTML sanitizado):
  tableData?: { headers: string[]; rows: string[][] };
}

interface UserPreferences {
  fontSize: 'sm' | 'md' | 'lg' | 'xl';
}

interface DocumentViewerProps {
  documentId: string;
  queryKey: string[];
  initialSections?: DocumentSection[];
  totalSections: number; // obrigatório para progresso "142 de 387" e controle de streaming

  // Retorna seções completas (nunca corta um artigo no meio)
  // hasMore: false indica fim do documento (diferencia de erro/transiente)
  contentLoader: (afterSectionId: string | null, limit: number, signal: AbortSignal) => Promise<{ 
    sections: DocumentSection[]; 
    hasMore: boolean 
  }>;

  searchQuery?: string;
  // matchIndex: índice global do match no documento (0 = primeiro match)
  // occurrenceInSection: qual ocorrência dentro da seção específica
  searchMatches?: Array<{ sectionId: string; matchIndex: number; occurrenceInSection: number }>;

  onNavigate: (sectionId: string) => void;
  onLoadError?: (error: Error, context: { loadedCount: number }) => void;
  preferences?: UserPreferences; // persistido via Zustand (fontSize apenas)
  onPreferencesChange?: (prefs: UserPreferences) => void;
}

// Imperative handle via ref:
interface DocumentViewerRef {
  scrollToMatch(matchIndex: number): void;  // computa target → virtuoso.scrollToIndex → highlight
  getVisibleSection(): string | null;       // retorna ID da seção atualmente visível
  setFontSize(size: 'sm' | 'md' | 'lg' | 'xl'): void;
}

// Estados: loading (skeleton) | ready | error | empty | partial-error (inline)
// Retry: TanStack Query gerencia retry automático; onLoadError para telemetry/UI de erro parcial
// Persistência: fontSize via Zustand + IndexedDB; progresso de leitura via URL hash (#artigo-5)
// a11y: role="article", aria-label dinâmico, role="mark" com aria-label para highlights
// Performance: react-virtuoso com endReached (respeitando hasMore), AbortSignal para cancelamento
// Deep-link: hook useDocumentDeepLink sincroniza URL hash → virtuoso.scrollToIndex com fetch prévio se necessário
```

### 4.5 BottomSheet (vaul)
```typescript
// vaul v0.9.x API: snapPoints aceita strings ('148px', '50vh', '92dvh') ou números (pixels)
type SnapPoint = `${number}px` | `${number}vh` | `${number}dvh` | number;

interface BottomSheetProps {
  snapPoints?: SnapPoint[];  // ex: ['25vh', '50vh', '92dvh'] ou [200, 400, 800]
  defaultSnap?: number;      // index inicial
  onSnapChange?: (index: number) => void;
  onDismiss?: () => void;
  backdrop?: boolean;
  closeOnBackdrop?: boolean;
  trapFocus?: boolean;
  preventScroll?: boolean;
  handle?: boolean;
  children: ReactNode;
}

// Utilitário obrigatório para converter unidades relativas em pixels (vaul espera pixels no cálculo interno):
function parseSnapPoints(points: SnapPoint[]): number[] {
  return points.map(p => {
    if (typeof p === 'number') return p;
    const match = p.match(/^(\d+(?:\.\d+)?)(px|vh|dvh)$/);
    if (!match) throw new Error(`Invalid snap point: ${p}`);
    const value = parseFloat(match[1]);
    const unit = match[2];
    if (unit === 'px') return value;
    const height = unit === 'dvh' ? window.innerHeight : document.documentElement.clientHeight;
    return (value / 100) * height;
  });
}

// Nota: vaul implementa focus trap, snap points e gestures nativamente (não é baseado em Radix Dialog)
```

